var el = document.querySelector(".reveal");
var words = el.textContent.split(" ");
el.innerHTML = words.map(function(w){ return "<span class=\"w\">" + w + "</span>"; }).join(" ");
var spans = el.querySelectorAll(".w");
spans.forEach(function(s, i){ s.style.transitionDelay = (i * 70) + "ms"; });
new IntersectionObserver(function(ents){
  ents.forEach(function(e){
    if (e.isIntersecting) spans.forEach(function(s){ s.classList.add("on"); });
  });
}, { threshold: 0.15 }).observe(el);

.reveal .ln { overflow: hidden; padding: 4px 0; }
.reveal .ln > span { display: inline-block; transform: translateY(115%); transition: transform 900ms cubic-bezier(0.22,1,0.36,1); }
.reveal .ln.on > span { transform: translateY(0); }

var lns = document.querySelectorAll(".reveal .ln");
new IntersectionObserver(function(ents){
  if (ents[0].isIntersecting) {
    lns.forEach(function(ln, i){ setTimeout(function(){ ln.classList.add("on"); }, i * 160); });
  }
}, { threshold: 0.2 }).observe(document.querySelector(".reveal"));

var el = document.querySelector(".reveal");
el.innerHTML = el.textContent.split("").map(function(c){ return "<span class=\"c\">" + (c === " " ? "&nbsp;" : c) + "</span>"; }).join("");
var spans = el.querySelectorAll(".c");
spans.forEach(function(s, i){ s.style.transitionDelay = (i * 70) + "ms"; });
spans.forEach(function(s){ s.classList.add("on"); });

.reveal { color: #525252; }
.reveal .w { display: inline-block; transition: color 200ms; }
.reveal .w.on { color: #fff; }

