// 라이브러리 없이 — sticky + scroll 이벤트
var spans = document.querySelectorAll(".reveal .w");
var stage = document.querySelector(".stage");
window.addEventListener("scroll", function(){
  var rect = stage.getBoundingClientRect();
  var p = Math.min(1, Math.max(0, -rect.top / (stage.parentElement.offsetHeight - window.innerHeight)));
  var idx = Math.floor(p * spans.length);
  spans.forEach(function(s, i){ s.classList.toggle("on", i < idx); });
}, { passive: true });

.reveal {
  background: linear-gradient(90deg, #ffffff 50%, #525252 50%);
  background-size: 200% 100%;
  background-position: 100% 0;
  -webkit-background-clip: text;
  background-clip: text;
  -webkit-text-fill-color: transparent;
  transition: background-position 1400ms cubic-bezier(0.22,1,0.36,1);
}
.reveal.on { background-position: 0 0; }

.reveal { overflow: hidden; padding: 14px 0; }
.reveal .c { display: inline-block; transform: translateY(-115%); transition: transform 800ms cubic-bezier(0.7,0,0.3,1); }
.reveal .c.on { transform: translateY(0); }

var el = document.querySelector(".reveal");
el.innerHTML = el.textContent.split("").map(function(c){ return "<span class=\"c\">" + (c === " " ? "&nbsp;" : c) + "</span>"; }).join("");
var spans = el.querySelectorAll(".c");
spans.forEach(function(s, i){ s.style.transitionDelay = (i * 80) + "ms"; });
spans.forEach(function(s){ s.classList.add("on"); });

.reveal {
  font-family: "Pretendard Variable","Pretendard",system-ui;
  font-variation-settings: "wght" 100;
  font-weight: 100;
  transition: font-variation-settings 1800ms cubic-bezier(0.4,0,0.2,1), font-weight 1800ms cubic-bezier(0.4,0,0.2,1);
}
.reveal.on {
  font-variation-settings: "wght" 900;
  font-weight: 900;
}

.reveal { display: inline-flex; flex-direction: column; gap: 12px; align-items: flex-start; }
.reveal .t { opacity: 0; transform: translateY(20px); transition: opacity 700ms, transform 700ms cubic-bezier(0.2,0,0,1); }
.reveal .u { display: block; height: 4px; width: 100%; background: currentColor; transform: scaleX(0); transform-origin: left; transition: transform 900ms cubic-bezier(0.22,1,0.36,1) 300ms; }
.reveal.on .t { opacity: 1; transform: translateY(0); }
.reveal.on .u { transform: scaleX(1); }
